arguments.command:
# Check how many crons still on anthropic vs kimi
echo "=== Cron model breakdown ==="
/opt/homebrew/bin/openclaw cron list 2>/dev/null | awk '
BEGIN {anthropic=0; kimi=0; gemma=0; deepseek=0; other=0; total=0}
/anthropic/ {anthropic++; total++}
/ollama\/kimi/ {kimi++; total++}
/ollama\/gemma/ {gemma++; total++}
/ollama\/deepseek/ {deepseek++; total++}
/ok|error|running/ && !/anthropic/ && !/kimi/ && !/gemma/ && !/deepseek/ {other++; total++}
END {
  print "Total crons: " total
  print "  Anthropic: " anthropic
  print "  kimi: " kimi
  print "  gemma4: " gemma
  print "  deepseek: " deepseek
  print "  Other: " other
}'

echo ""
echo "=== Anthropic crons remaining ==="
/opt/homebrew/bin/openclaw cron list 2>/dev/null | grep "anthropic" | awk '{print $1, $2}' | head -10
